/**
 * Dialogos Observer
 * 
 * Real-time integration of Living Dialogos into the substrate flow.
 * Uses singleton pattern to persist across sessions.
 */

import { LivingDialogos, type StatedIntent } from './live.js';
import * as fs from 'fs';
import * as path from 'path';

const DIALOGOS_STATE_FILE = path.join('history', 'dialogos_state.json');

export interface ObserverConfig {
  enabled: boolean;
  checkInterval: number;
  interruptOnGap: boolean;
  interruptOnMisalignment: boolean;
  minSessionActivity: number;
}

export const DEFAULT_OBSERVER_CONFIG: ObserverConfig = {
  enabled: true,
  checkInterval: 300000,
  interruptOnGap: true,
  interruptOnMisalignment: true,
  minSessionActivity: 5
};

export class DialogosObserver {
  private dialogos: LivingDialogos;
  private config: ObserverConfig;
  private actionCount: number = 0;
  private lastCheck: number = Date.now();
  private sessionStart: number = Date.now();
  private storedIntents: Map<string, StatedIntent[]> = new Map();
  private storedActions: Map<string, any[]> = new Map();

  constructor(config: Partial<ObserverConfig> = {}) {
    this.dialogos = new LivingDialogos();
    this.config = { ...DEFAULT_OBSERVER_CONFIG, ...config };
    this.loadState();
  }

  private loadState() {
    try {
      if (fs.existsSync(DIALOGOS_STATE_FILE)) {
        const state = JSON.parse(fs.readFileSync(DIALOGOS_STATE_FILE, 'utf-8'));
        this.storedIntents = new Map(Object.entries(state.intents || {}));
        this.storedActions = new Map(Object.entries(state.actions || {}));
      }
    } catch (e) { console.error("[Dialogos Observer] Failed to load state:", e); }
  }

  saveState() {
    try {
      const state = {
        intents: Object.fromEntries(this.storedIntents),
        actions: Object.fromEntries(this.storedActions),
        savedAt: new Date().toISOString()
      };
      fs.writeFileSync(DIALOGOS_STATE_FILE, JSON.stringify(state, null, 2));
    } catch (e) { console.error("[Dialogos Observer] Failed to save state:", e); }
  }

  recordAction(type: string, description: string): string | null {
    this.actionCount++;
    this.dialogos.indexSemanticContent(`current_${Date.now()}`, description);

    if (this.shouldInterrupt()) {
      const interruption = this.generateInterruption();
      if (interruption) {
        this.saveState();
        return interruption;
      }
    }
    return null;
  }

  registerStatedIntent(subject: string, description: string, emotionalTone?: string) {
    const intent: StatedIntent = {
      id: `intent_${Date.now()}`,
      description,
      timestamp: Date.now(),
      sessionId: 'current'
    };
    if (emotionalTone) intent.emotionalTone = emotionalTone;
    this.dialogos.registerIntent(subject, intent);

    // Also store persistently
    const existing = this.storedIntents.get(subject) || [];
    existing.push(intent);
    this.storedIntents.set(subject, existing);
    this.saveState();
  }
  /**
   * Mark an intent as completed and remove it from tracking.
   */
  completeIntent(subject: string, intentId: string): boolean {
    const result = this.dialogos.completeIntent(subject, intentId);

/**
 * The AkmeEngine
 * 
 * "akmД“" - Greek for point, edge, highest degree
 * The engine that knows when to stop to go further.
 */

import type {
  Suspension,
  WaitingQuestion,
  Threshold,
  ThresholdType,
  Resolution,
  AkmeConfig,
  Timing,
} from './types.js';
import { DEFAULT_AKME_CONFIG } from './types.js';

export class AkmeEngine {
  private suspensions: Map<string, Suspension> = new Map();
  private questions: Map<string, WaitingQuestion> = new Map();
  private config: AkmeConfig;
  private resolvedSuspensions: Resolution[] = [];

  constructor(config: Partial<AkmeConfig> = {}) {
    this.config = { ...DEFAULT_AKME_CONFIG, ...config };
  }

  detectThreshold(context: string, indicators: string[]): Threshold | null {
    const detectedType = this.matchToThreshold(context, indicators);
    if (!detectedType || !this.config.triggerThresholds.includes(detectedType)) {
      return null;
    }

    const confidence = this.calculateConfidence(context, indicators, detectedType);

    return {
      type: detectedType,
      detectedAt: Date.now(),
      confidence,
      indicators,
      suggestedAction: this.suggestAction(detectedType, confidence),
    };
  }

  suspend(
    reason: string,
    thresholdType: ThresholdType,
    questions: WaitingQuestion[],
    context: Suspension['context']
  ): Suspension {
    if (this.suspensions.size >= this.config.maxSuspensions) {
      throw new Error(`Maximum suspensions reached (${this.config.maxSuspensions})`);
    }

    const suspension: Suspension = {
      id: `susp_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
      startedAt: Date.now(),
      reason,
      thresholdType,
      questions,
      context,
      notes: [],
    };

    this.suspensions.set(suspension.id, suspension);

    for (const q of questions) {
      this.questions.set(q.id, q);
    }

    return suspension;
  }

  addNote(suspensionId: string, note: string): void {
    const suspension = this.suspensions.get(suspensionId);
    if (!suspension) throw new Error(`Suspension not found: ${suspensionId}`);
    suspension.notes.push(`[${new Date().toISOString()}] ${note}`);
  }

  calculateTiming(suspension: Suspension): Timing {
    const heldDuration = Date.now() - suspension.startedAt;
    const base = this.config.minHoldTime;
    const multiplier = suspension.questions.length * 0.5;

    const additionalTime = Math.min(heldDuration * multiplier, 300000);

    return {
      optimalResume: Date.now() + Math.max(base - heldDuration, 30000),
      factors: [
        `Base hold: ${base}ms`,
        `Question load: ${suspension.questions.length}`,
        `Threshold type: ${suspension.thresholdType}`,
        `Already held: ${heldDuration}ms`,
      ],
    };
  }

